import{_ as t,o,c as a,ag as r}from"./chunks/framework.BPmc_f4o.js";const b=JSON.parse('{"title":"brut test run","description":"","frontmatter":{},"headers":[],"relativePath":"brut-cli-commands/commands/run.md","filePath":"brut-cli-commands/commands/run.md"}'),s={name:"brut-cli-commands/commands/run.md"};function n(l,e,i,d,u,c){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="brut-test-run" tabindex="-1"><code>brut test run</code> <a class="header-anchor" href="#brut-test-run" aria-label="Permalink to &quot;`brut test run`&quot;">​</a></h1><p>Run non-e2e tests</p><h2 id="usage" tabindex="-1">USAGE <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;USAGE&quot;">​</a></h2><pre><code>brut test run [options] specs_to_run...\n</code></pre><h2 id="description" tabindex="-1">DESCRIPTION <a class="header-anchor" href="#description" aria-label="Permalink to &quot;DESCRIPTION&quot;">​</a></h2><p>Runs all non end-to-end tests for the app, or runs a subset of non-end-to-end tests using RSpec-style syntax. Do note that you cannot use this command to run an end-to-end test, since those require the test server to be running.</p><h2 id="options" tabindex="-1">OPTIONS <a class="header-anchor" href="#options" aria-label="Permalink to &quot;OPTIONS&quot;">​</a></h2><ul><li><code>--env=ENVIRONMENT</code> - Project environment, e.g. test, development, production. Default depends on the command</li><li><code>--log-level=LOG_LEVEL</code> - Log level, which should be debug, info, warn, error, or fatal. Defaults to error</li><li><code>--debug, --verbose</code> - Set log level to debug, and show log messages on stdout</li><li><code>--quiet</code> - Set log level to error</li><li><code>--log-file=FILE</code> - Path to a file where log messages are written. Defaults to $XDG_CACHE_HOME/brut/logs/brut.log</li><li><code>--[no-]log-stdout</code> - Log messages to stdout in addition to the log file</li><li><code>--help, -h</code> - Show help</li><li><code>--[no-]rebuild</code> - If true, test database is rebuilt before tests are run (default false)</li><li><code>--[no-]rebuild-after</code> - If true, test database is rebuilt after tests are run (default false)</li><li><code>--seed=SEED</code> - Set the random seed to allow duplicating a test run</li></ul><h2 id="environment-variables" tabindex="-1">ENVIRONMENT VARIABLES <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;ENVIRONMENT VARIABLES&quot;">​</a></h2><ul><li><code>LOGGER_LEVEL_FOR_TESTS</code> - Can be set to debug, info, warn, error, or fatal to control logging during tests. Defaults to &#39;warn&#39; to avoid verbose test output</li><li><code>RSPEC_PROFILE_EXAMPLES</code> - If set to any value, it is converted to an int and set as RSpec&#39;s number of examples to profile. NOTE: this is used in the app&#39;s spec_helper.rb so could&#39;ve been removed</li><li><code>RSPEC_WARNINGS</code> - If set to &#39;true&#39;, configures RSpec warnings for the test run. NOTE: this is used in the app&#39;s spec_helper.rb so could&#39;ve been removed</li></ul>',10)])])}const p=t(s,[["render",n]]);export{b as __pageData,p as default};
